<template>
  <div class="editor-container">
    <el-card class="box-card">
      <template #header>
        <div class="card-header">
          <span>{{ isEdit ? '编辑文章' : '新建文章' }}</span>
          <el-button-group>
            <el-button type="primary" @click="handleSave(false)" :loading="saving">保存草稿</el-button>
            <el-button type="success" @click="handleSave(true)" :loading="saving">发布文章</el-button>
          </el-button-group>
        </div>
      </template>

      <el-form :model="form" label-width="80px">
        <el-form-item label="文章标题">
          <el-input v-model="form.zh.title" placeholder="请输入中文标题" size="large" />
        </el-form-item>

        <el-form-item label="摘要描述">
          <el-input v-model="form.zh.description" placeholder="简要描述文章内容（用于列表页展示）" />
        </el-form-item>

        <el-form-item label="正文内容">
          <el-input 
            v-model="form.zh.content" 
            type="textarea" 
            :rows="15" 
            placeholder="在此输入中文正文...&#10;支持 Markdown 语法&#10;（系统会自动将此处内容翻译为日文和英文）"
            style="font-family: monospace; font-size: 14px;"
          />
        </el-form-item>

        <el-row :gutter="20">
          <el-col :span="12">
            <el-form-item label="分类">
              <el-select v-model="form.category" placeholder="选择分类">
                <el-option label="工作" value="work" />
                <el-option label="生活" value="life" />
                <el-option label="随想" value="thoughts" />
              </el-select>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="标签">
              <el-input v-model="form.tagsStr" placeholder="用逗号分隔，如：日本，ECU" />
            </el-form-item>
          </el-col>
        </el-row>

        <!-- 翻译结果预览区 -->
        <el-divider content-position="left">🌐 多语言预览 (保存后更新)</el-divider>
        
        <el-tabs v-model="activeTab">
		 <el-tab-pane label="English" name="en">
		   <div class="lang-preview-box">
             <h3>{{ article.en?.title || 'Translation pending...' }}</h3>
             <p>{{ article.en?.content || 'Save the article to see the translation.' }}</p>
           </div>
		 </el-tab-pane>
          <el-tab-pane label="日本語" name="ja">
            <div class="lang-preview-box">
              <h3>{{ article.ja?.title || '翻訳待ち...' }}</h3>
              <p>{{ article.ja?.content || '記事を保存して翻訳を確認してください。' }}</p>
            </div>
          </el-tab-pane>
        </el-tabs>
      </el-form>
    </el-card>
  </div>
</template>

<script setup>
import { ref, reactive, onMounted, computed } from 'vue';
import { useRoute, useRouter } from 'vue-router';
import { ElMessage } from 'element-plus';
import request from '../api/request.js';

const route = useRoute();
const router = useRouter();

const isEdit = computed(() => !!route.params.id);
const saving = ref(false);
const activeTab = ref('ja');
const article = ref({});

const form = reactive({
  id: null,
  zh: { title: '', description: '', content: '' },
  category: 'work',
  tagsStr: '',
  status: 'draft'
});

// 加载数据
onMounted(async () => {
  if (isEdit.value) {
    try {
      const res = await request.get(`/articles/${route.params.id}`);
      if (res.success) {
        article.value = res.data;
        form.id = res.data.id;
        form.zh = { ...res.data.zh };
        form.category = res.data.category;
        form.tagsStr = res.data.tags ? res.data.tags.join(', ') : '';
        form.status = res.data.status;
      }
    } catch (err) {
      ElMessage.error('加载文章失败');
    }
  }
});

// 保存逻辑
const handleSave = async (publish = false) => {
  if (!form.zh.title || !form.zh.content) {
    return ElMessage.warning('标题和正文内容不能为空');
  }

  saving.value = true;
  form.status = publish ? 'published' : 'draft';
  const payload = {
    title: form.zh.title,
    description: form.zh.description,
    content: form.zh.content,
    category: form.category,
    tags: form.tagsStr.split(/[,，]/).map(t => t.trim()).filter(t => t),
    status: form.status
  };

  try {
    let res;
    if (isEdit.value) {
      res = await request.put(`/articles/${form.id}`, payload);
    } else {
      res = await request.post('/articles', payload);
    }

    if (res.success) {
      ElMessage.success(publish ? '文章已发布，并自动翻译为日/英文！' : '草稿已保存，翻译已生成');
      article.value = res.data; // 更新预览
      // 如果是新建，跳转到编辑页以便继续操作
      if (!isEdit.value) router.replace(`/articles/edit/${res.data.id}`);
    }
  } catch (err) {
    console.error(err);
  } finally {
    saving.value = false;
  }
};
</script>

<style scoped>
.editor-container { max-width: 1000px; margin: 0 auto; }
.card-header { display: flex; justify-content: space-between; align-items: center; }
.lang-preview-box { padding: 20px; background: #f9f9f9; border-radius: 4px; min-height: 100px; }
.lang-preview-box h3 { color: #606266; margin-bottom: 10px; }
.lang-preview-box p { color: #909399; line-height: 1.6; white-space: pre-wrap; }
</style>